     1→/**
     2→ * @strand/core — header initialization and validation
     3→ *
     4→ * The Strand header occupies the first 512 bytes of every SharedArrayBuffer
     5→ * managed by this library. It contains:
     6→ *
     7→ *   Static geometry  — magic, version, schema fingerprint, ring capacities,
     8→ *                      and a CRC of those six fields (header_crc)
     9→ *   Atomics words    — seven i32 cursors (including CTRL_ABORT)
    10→ *   Schema bytes     — binary-encoded BinarySchemaDescriptor
    11→ *
    12→ * initStrandHeader()  — called once by the party that allocates the SAB.
    13→ *                       Safe to call before sharing the SAB with any Worker.
    14→ * readStrandHeader()  — called by consumers (StrandView, Workers) to validate
    15→ *                       and reconstruct the StrandMap from the binary header.
    16→ * computeStrandMap()  — server-side convenience: build a StrandMap from
    17→ *                       schema + sizing parameters.
    18→ */
    19→
    20→import {
    21→  STRAND_MAGIC,
    22→  STRAND_VERSION,
    23→  HEADER_SIZE,
    24→  MAX_SCHEMA_BYTES,
    25→  OFFSET_MAGIC,
    26→  OFFSET_VERSION,
    27→  OFFSET_SCHEMA_FP,
    28→  OFFSET_RECORD_STRIDE,
    29→  OFFSET_INDEX_CAPACITY,
    30→  OFFSET_HEAP_CAPACITY,
    31→  OFFSET_HEADER_CRC,
    32→  OFFSET_SCHEMA_BYTE_LEN,
    33→  OFFSET_SCHEMA_BYTES,
    34→  CTRL_ARRAY_LEN,
    35→  CTRL_WRITE_SEQ,
    36→  CTRL_COMMIT_SEQ,
    37→  CTRL_READ_CURSOR,
    38→  CTRL_STATUS,
    39→  CTRL_HEAP_WRITE,
    40→  CTRL_HEAP_COMMIT,
    41→  CTRL_ABORT,
    42→  CTRL_CONSUMER_BASE,
    43→  MAX_CONSUMERS,
    44→  CONSUMER_SLOT_VACANT,
    45→  STATUS_INITIALIZING,
    46→  computeTotalBytes,
    47→} from './constants';
    48→import { encodeSchema, decodeSchema, schemaFingerprint } from './schema';
    49→import type { StrandMap, BinarySchemaDescriptor } from './types';
    50→
    51→// ─── Errors ───────────────────────────────────────────────────────────────────
    52→
    53→export class StrandHeaderError extends Error {
    54→  constructor(message: string) {
    55→    super(message);
    56→    this.name = 'StrandHeaderError';
    57→  }
    58→}
    59→
    60→// ─── Internal helpers ─────────────────────────────────────────────────────────
    61→
    62→/**
    63→ * FNV-1a 32-bit hash — inlined here to avoid cross-module coupling.
    64→ * Used exclusively for computing and validating the header geometry CRC.
    65→ */
    66→function fnv1a32(bytes: Uint8Array): number {
    67→  let hash = 0x811c9dc5;
    68→  for (const byte of bytes) {
    69→    hash ^= byte;
    70→    hash  = Math.imul(hash, 0x01000193);
    71→  }
    72→  return hash >>> 0;
    73→}
    74→
    75→/**
    76→ * Compute the header geometry CRC from the six static fields (bytes 0–23).
    77→ * Written at OFFSET_HEADER_CRC by initStrandHeader; re-computed and compared
    78→ * by readStrandHeader before any geometry value is used.
    79→ */
    80→function computeHeaderCRC(sab: SharedArrayBuffer): number {
    81→  return fnv1a32(new Uint8Array(sab, 0, OFFSET_HEADER_CRC));
    82→}
    83→
    84→function isPowerOfTwo(n: number): boolean {
    85→  return n > 0 && (n & (n - 1)) === 0;
    86→}
    87→
    88→// ─── initStrandHeader ─────────────────────────────────────────────────────────
    89→
    90→/**
    91→ * Write the Strand header into a freshly allocated SharedArrayBuffer.
    92→ *
    93→ * Pre-conditions (enforced; throws StrandHeaderError on violation):
    94→ *   - Platform must be little-endian (BE systems are unsupported)
    95→ *   - sab.byteLength >= map.total_bytes
    96→ *   - map.index_capacity is a power of 2
    97→ *   - map.record_stride is 4-byte aligned
    98→ *   - Binary schema fits in the 452-byte header region
    99→ *   - map.schema_fingerprint matches the actual fingerprint of map.schema
   100→ *
   101→ * Writes static fields, computes and stores header_crc, then initializes
   102→ * all seven Atomics control words to zero with Atomics.store (release
   103→ * semantics). Any Worker that receives this SAB via postMessage after
   104→ * initStrandHeader returns will see the correctly initialized header.
   105→ *
   106→ * Call this exactly once, before sharing the SAB with any Worker.
   107→ */
   108→export function initStrandHeader(sab: SharedArrayBuffer, map: StrandMap): void {
   109→
   110→  // ── Pre-flight: endianness ─────────────────────────────────────────────────
   111→  //
   112→  // All multi-byte DataView reads/writes in @strand/core use explicit
   113→  // little-endian (true). The Atomics control words are accessed via
   114→  // Int32Array, which uses native byte order — but since producer and
   115→  // consumer always share the same process, their native order is always
   116→  // identical regardless of platform.
   117→  //
   118→  // However, we still refuse big-endian as a defensive measure: running on a
   119→  // BE system would mean a future code path might mix DataView-LE and
   120→  // TypedArray-BE interpretations of the same header bytes, producing
   121→  // silent data corruption that is very hard to debug.
   122→  //
   123→  // The probe byte sequence [0x01, 0x00] reads as 0x0001 on LE and 0x0100 on BE.
   124→  if (new Uint16Array(new Uint8Array([0x01, 0x00]).buffer)[0] !== 1) {
   125→    throw new StrandHeaderError(
   126→      '@strand/core requires a little-endian system. ' +
   127→      'Big-endian platforms are not supported in v' + STRAND_VERSION + '.',
   128→    );
   129→  }
   130→
   131→  // ── Pre-flight: size ───────────────────────────────────────────────────────
   132→
   133→  if (sab.byteLength < HEADER_SIZE) {
   134→    throw new StrandHeaderError(
   135→      `SharedArrayBuffer too small: ${sab.byteLength} bytes; ` +
   136→      `need at least ${HEADER_SIZE} for the header alone.`,
   137→    );
   138→  }
   139→
   140→  const expectedTotal = computeTotalBytes(
   141→    map.index_capacity,
   142→    map.record_stride,
   143→    map.heap_capacity,
   144→  );
   145→  if (sab.byteLength < expectedTotal) {
   146→    throw new StrandHeaderError(
   147→      `SharedArrayBuffer too small for this StrandMap: ` +
   148→      `need ${expectedTotal} bytes ` +
   149→      `(header:${HEADER_SIZE} + index:${map.index_capacity * map.record_stride} + heap:${map.heap_capacity}), ` +
   150→      `got ${sab.byteLength}.`,
   151→    );
   152→  }
   153→
   154→  // ── Pre-flight: alignment ──────────────────────────────────────────────────
   155→
   156→  if (!isPowerOfTwo(map.index_capacity)) {
   157→    throw new StrandHeaderError(
   158→      `index_capacity must be a power of 2 for O(1) ring arithmetic; ` +
   159→      `got ${map.index_capacity}.`,
   160→    );
   161→  }
   162→
   163→  if (map.record_stride % 4 !== 0) {
   164→    throw new StrandHeaderError(
   165→      `record_stride must be 4-byte aligned for DataView alignment safety; ` +
   166→      `got ${map.record_stride}.`,
   167→    );
   168→  }
   169→
   170→  // ── Pre-flight: schema ─────────────────────────────────────────────────────
   171→
   172→  const schemaBytes = encodeSchema(map.schema);
   173→  if (schemaBytes.length > MAX_SCHEMA_BYTES) {
   174→    throw new StrandHeaderError(
   175→      `Schema binary encoding is ${schemaBytes.length} bytes; ` +
   176→      `maximum that fits in the header is ${MAX_SCHEMA_BYTES} bytes. ` +
   177→      `Reduce field count or shorten field names.`,
   178→    );
   179→  }
   180→
   181→  // Reject a StrandMap whose fingerprint disagrees with its schema.
   182→  const actualFp = schemaFingerprint(map.schema);
   183→  if (actualFp !== map.schema_fingerprint) {
   184→    throw new StrandHeaderError(
   185→      `schema_fingerprint mismatch: ` +
   186→      `StrandMap declares 0x${map.schema_fingerprint.toString(16).padStart(8, '0')}, ` +
   187→      `but schema encodes to    0x${actualFp.toString(16).padStart(8, '0')}. ` +
   188→      `Use computeStrandMap() to derive the fingerprint automatically.`,
   189→    );
   190→  }
   191→
   192→  // ── Write static fields via DataView ──────────────────────────────────────
   193→
   194→  const view = new DataView(sab);
   195→
   196→  view.setUint32(OFFSET_MAGIC,           STRAND_MAGIC,           /* le */ true);
   197→  view.setUint32(OFFSET_VERSION,         STRAND_VERSION,                  true);
   198→  view.setUint32(OFFSET_SCHEMA_FP,       map.schema_fingerprint,          true);
   199→  view.setUint32(OFFSET_RECORD_STRIDE,   map.record_stride,               true);
   200→  view.setUint32(OFFSET_INDEX_CAPACITY,  map.index_capacity,              true);
   201→  view.setUint32(OFFSET_HEAP_CAPACITY,   map.heap_capacity,               true);
   202→
   203→  // ── Write header CRC ───────────────────────────────────────────────────────
   204→  //
   205→  // The CRC covers bytes 0–23 (the six static geometry fields written above).
   206→  // It is the last static field written so that the six geometry values are
   207→  // already stable when the hash is computed. readStrandHeader re-computes
   208→  // the same hash before using any geometry value, catching rogue-pointer
   209→  // corruption of index_capacity, record_stride, or heap_capacity.
   210→
   211→  view.setUint32(OFFSET_HEADER_CRC, computeHeaderCRC(sab), true);
   212→
   213→  // ── Write schema ───────────────────────────────────────────────────────────
   214→
   215→  view.setUint32(OFFSET_SCHEMA_BYTE_LEN, schemaBytes.length, true);
   216→  new Uint8Array(sab, OFFSET_SCHEMA_BYTES, schemaBytes.length).set(schemaBytes);
   217→
   218→  // ── Initialize Atomics control words ──────────────────────────────────────
   219→  //
   220→  // Atomics.store — not plain assignment — because the SAB may be shared by
   221→  // the time this function returns. Atomics.store provides release semantics:
   222→  // any Worker receiving the SAB via postMessage will observe these values.
   223→
   224→  const ctrl = new Int32Array(sab, 0, CTRL_ARRAY_LEN);
   225→
   226→  Atomics.store(ctrl, CTRL_WRITE_SEQ,   0);
   227→  Atomics.store(ctrl, CTRL_COMMIT_SEQ,  0);
   228→  Atomics.store(ctrl, CTRL_READ_CURSOR, 0);
   229→  Atomics.store(ctrl, CTRL_STATUS,      STATUS_INITIALIZING);
   230→  Atomics.store(ctrl, CTRL_HEAP_WRITE,  0);
   231→  Atomics.store(ctrl, CTRL_HEAP_COMMIT, 0);
   232→  Atomics.store(ctrl, CTRL_ABORT,       0);
   233→
   234→  // Initialize all consumer cursor slots to VACANT.
   235→  // registerConsumer() claims a slot via CAS; releaseConsumer() restores VACANT.
   236→  for (let i = 0; i < MAX_CONSUMERS; i++) {
   237→    Atomics.store(ctrl, CTRL_CONSUMER_BASE + i, CONSUMER_SLOT_VACANT);
   238→  }
   239→}
   240→
   241→// ─── readStrandHeader ─────────────────────────────────────────────────────────
   242→
   243→/**
   244→ * Read and strictly validate the Strand header in a SharedArrayBuffer.
   245→ *
   246→ * Throws StrandHeaderError on:
   247→ *   - Magic mismatch        (buffer was not written by @strand/core)
   248→ *   - Version mismatch      (written by an incompatible version)
   249→ *   - Header CRC mismatch   (geometry fields corrupted since initStrandHeader)
   250→ *   - Corrupt schema        (truncated or unknown type tags)
   251→ *   - Fingerprint mismatch  (schema bytes inconsistent with stored fingerprint)
   252→ *
   253→ * Validation order is fastest-to-detect-corruption first:
   254→ *   magic → version → header_crc → schema decode → schema fingerprint
   255→ */
   256→export function readStrandHeader(sab: SharedArrayBuffer): StrandMap {
   257→  if (sab.byteLength < HEADER_SIZE) {
   258→    throw new StrandHeaderError(
   259→      `SharedArrayBuffer is ${sab.byteLength} bytes; ` +
   260→      `a Strand header requires at least ${HEADER_SIZE}.`,
   261→    );
   262→  }
   263→
   264→  const view = new DataView(sab);
   265→
   266→  // ── Magic ──────────────────────────────────────────────────────────────────
   267→
   268→  const magic = view.getUint32(OFFSET_MAGIC, true);
   269→  if (magic !== STRAND_MAGIC) {
   270→    const hex = `0x${magic.toString(16).toUpperCase().padStart(8, '0')}`;
   271→    throw new StrandHeaderError(
   272→      `Invalid magic: got ${hex}; expected 0x${STRAND_MAGIC.toString(16).toUpperCase()} ('STRN'). ` +
   273→      `This SharedArrayBuffer was not initialized by @strand/core.`,
   274→    );
   275→  }
   276→
   277→  // ── Version ────────────────────────────────────────────────────────────────
   278→
   279→  const version = view.getUint32(OFFSET_VERSION, true);
   280→  if (version !== STRAND_VERSION) {
   281→    throw new StrandHeaderError(
   282→      `Unsupported Strand version ${version}. ` +
   283→      `This build of @strand/core supports version ${STRAND_VERSION} only. ` +
   284→      `Update @strand/core to read version-${version} buffers.`,
   285→    );
   286→  }
   287→
   288→  // ── Header CRC ────────────────────────────────────────────────────────────
   289→  //
   290→  // Re-compute the FNV-1a hash of the six static geometry fields (bytes 0–23)
   291→  // and compare to the stored checksum at OFFSET_HEADER_CRC. A mismatch means
   292→  // a rogue pointer or memory safety bug has corrupted one of the geometry
   293→  // fields since initStrandHeader ran. Halt before using any corrupt value.
   294→
   295→  const storedCRC   = view.getUint32(OFFSET_HEADER_CRC, true);
   296→  const computedCRC = computeHeaderCRC(sab);
   297→  if (storedCRC !== computedCRC) {
   298→    throw new StrandHeaderError(
   299→      `Header geometry CRC mismatch: ` +
   300→      `stored 0x${storedCRC.toString(16).padStart(8, '0')}, ` +
   301→      `computed 0x${computedCRC.toString(16).padStart(8, '0')}. ` +
   302→      `One of the static geometry fields (magic, version, schema_fp, ` +
   303→      `record_stride, index_capacity, or heap_capacity) was corrupted ` +
   304→      `after initStrandHeader().`,
   305→    );
   306→  }
   307→
   308→  // ── Geometry ───────────────────────────────────────────────────────────────
   309→
   310→  const schema_fingerprint = view.getUint32(OFFSET_SCHEMA_FP,       true);
   311→  const record_stride      = view.getUint32(OFFSET_RECORD_STRIDE,    true);
   312→  const index_capacity     = view.getUint32(OFFSET_INDEX_CAPACITY,   true);
   313→  const heap_capacity      = view.getUint32(OFFSET_HEAP_CAPACITY,    true);
   314→  const schema_byte_len    = view.getUint32(OFFSET_SCHEMA_BYTE_LEN,  true);
   315→
   316→  if (schema_byte_len < 2) {
   317→    throw new StrandHeaderError(
   318→      `schema_byte_len ${schema_byte_len} is too small: ` +
   319→      `minimum 2 bytes for the field_count u16. The header is corrupt.`,
   320→    );
   321→  }
   322→
   323→  if (schema_byte_len > MAX_SCHEMA_BYTES) {
   324→    throw new StrandHeaderError(
   325→      `schema_byte_len ${schema_byte_len} exceeds header capacity ${MAX_SCHEMA_BYTES}. ` +
   326→      `The header is corrupt.`,
   327→    );
   328→  }
   329→
   330→  // ── Schema ─────────────────────────────────────────────────────────────────
   331→
   332→  const schemaSlice = new Uint8Array(sab, OFFSET_SCHEMA_BYTES, schema_byte_len);
   333→  const schema      = decodeSchema(schemaSlice);
   334→  if (schema === null) {
   335→    throw new StrandHeaderError(
   336→      `Failed to decode schema descriptor (${schema_byte_len} bytes). ` +
   337→      `The header is corrupt or was written by an incompatible version.`,
   338→    );
   339→  }
   340→
   341→  if (schema.record_stride === 0) {
   342→    throw new StrandHeaderError(
   343→      `Decoded schema has record_stride = 0 (no fields or all zero-width fields). ` +
   344→      `A valid Strand schema must have at least one field. The header is corrupt.`,
   345→    );
   346→  }
   347→
   348→  // ── Fingerprint integrity ──────────────────────────────────────────────────
   349→
   350→  const computedFp = schemaFingerprint(schema);
   351→  if (computedFp !== schema_fingerprint) {
   352→    throw new StrandHeaderError(
   353→      `Schema fingerprint mismatch: ` +
   354→      `header stores 0x${schema_fingerprint.toString(16).padStart(8, '0')}, ` +
   355→      `decoded schema hashes to 0x${computedFp.toString(16).padStart(8, '0')}. ` +
   356→      `The schema descriptor in the header is corrupt.`,
   357→    );
   358→  }
   359→
   360→  // ── Stride coherence ───────────────────────────────────────────────────────
   361→  //
   362→  // decodeSchema() recomputes record_stride from field layout (high-water mark
   363→  // of byteOffset + field_width, padded to 4 bytes). The geometry section
   364→  // stores the stride independently. They must agree.
   365→  //
   366→  // A mismatch means either:
   367→  //   a) A hand-crafted BinarySchemaDescriptor set record_stride < field layout
   368→  //      (stride overflow — fields alias adjacent slots), or
   369→  //   b) The geometry section was corrupted after initStrandHeader ran (caught
   370→  //      by the CRC above for most cases, but the schema bytes are not CRC'd).
   371→  //
   372→  // If the decoded stride is larger, a writer using the geometry stride would
   373→  // write slots too close together and a reader at byteOffset would alias into
   374→  // the next slot — silent memory corruption.
   375→
   376→  if (schema.record_stride !== record_stride) {
   377→    throw new StrandHeaderError(
   378→      `Schema stride mismatch: geometry header stores record_stride=${record_stride}, ` +
   379→      `but field layout implies record_stride=${schema.record_stride}. ` +
   380→      `The header is corrupt or was written with a hand-crafted schema descriptor.`,
   381→    );
   382→  }
   383→
   384→  // ── Reconstruct StrandMap ──────────────────────────────────────────────────
   385→
   386→  return {
   387→    schema_fingerprint,
   388→    record_stride,
   389→    index_capacity,
   390→    heap_capacity,
   391→    total_bytes: computeTotalBytes(index_capacity, record_stride, heap_capacity),
   392→    // Query context is not stored in the binary header.
   393→    query: { assembly: '', chrom: '', start: 0, end: 0 },
   394→    estimated_records: 0,
   395→    schema,
   396→  };
   397→}
   398→
   399→// ─── computeStrandMap ─────────────────────────────────────────────────────────
   400→
   401→/**
   402→ * Server-side convenience: build a validated StrandMap from a schema and sizing
   403→ * parameters. Computes schema_fingerprint and total_bytes automatically.
   404→ *
   405→ * The returned StrandMap is ready to:
   406→ *   1. Embed in HTML as window.__STRAND_MAP__
   407→ *   2. Pass to initStrandHeader() to write the binary header
   408→ */
   409→export function computeStrandMap(params: {
   410→  schema:            BinarySchemaDescriptor;
   411→  index_capacity:    number;
   412→  heap_capacity:     number;
   413→  query:             StrandMap['query'];
   414→  estimated_records: number;
   415→}): StrandMap {
   416→  const { schema, index_capacity, heap_capacity, query, estimated_records } = params;
   417→
   418→  if (!isPowerOfTwo(index_capacity)) {
   419→    throw new StrandHeaderError(
   420→      `index_capacity must be a power of 2; got ${index_capacity}.`,
   421→    );
   422→  }
   423→
   424→  if (query.start > query.end) {
   425→    throw new RangeError(
   426→      `query.start (${query.start}) must be ≤ query.end (${query.end}). ` +
   427→      `A negative-length interval is not representable.`,
   428→    );
   429→  }
   430→
   431→  const hasVarLen = schema.fields.some(f => f.type === 'utf8' || f.type === 'json');
   432→  if (hasVarLen && heap_capacity === 0) {
   433→    throw new RangeError(
   434→      `Schema contains variable-length fields (utf8/json) but heap_capacity is 0. ` +
   435→      `claimHeap() would compute heapWrite % 0 = NaN, silently aliasing all ` +
   436→      `heap pointers to physOffset 0. Set heap_capacity > 0.`,
   437→    );
   438→  }
   439→
   440→  return {
   441→    schema_fingerprint: schemaFingerprint(schema),
   442→    record_stride:      schema.record_stride,
   443→    index_capacity,
   444→    heap_capacity,
   445→    total_bytes:        computeTotalBytes(index_capacity, schema.record_stride, heap_capacity),
   446→    query,
   447→    estimated_records,
   448→    schema,
   449→  };
   450→}
