     1→/**
     2→ * @strand/core — binary schema encoding, decoding, fingerprinting
     3→ *
     4→ * The schema is stored in binary form in the Strand header. The FNV-1a
     5→ * fingerprint of this binary encoding is schema_fingerprint. A reader
     6→ * validates the fingerprint on attach — type mismatch fails fast before
     7→ * any data access is attempted.
     8→ *
     9→ * Wire format for the binary schema descriptor (all values little-endian):
    10→ *
    11→ *   [field_count: u16]
    12→ *   For each field (variable length, padded to 4-byte boundary):
    13→ *     [type_tag:    u8]
    14→ *     [flags:       u8]
    15→ *     [byte_offset: u16]  ← explicit; no alignment guessing on decode
    16→ *     [name_len:    u8]
    17→ *     [name_bytes:  name_len × u8, UTF-8]
    18→ *     [padding:     0–3 zero bytes to next 4-byte boundary]
    19→ */
    20→
    21→import {
    22→  FIELD_BYTE_WIDTHS,
    23→  FIELD_FLAG_NULLABLE,
    24→  type FieldDescriptor,
    25→  type BinarySchemaDescriptor,
    26→  type FieldType,
    27→} from './types';
    28→
    29→// ─── Type Tag Mappings ────────────────────────────────────────────────────────
    30→
    31→const TYPE_TO_TAG: Readonly<Record<FieldType, number>> = {
    32→  i32: 0, u32: 1, i64: 2, f32: 3, f64: 4,
    33→  u16: 5, u8:  6, bool8: 7, utf8: 8, utf8_ref: 9, json: 10,
    34→  bytes: 11, i32_array: 12, f32_array: 13,
    35→};
    36→
    37→const TAG_TO_TYPE: Readonly<Record<number, FieldType>> = {
    38→  0: 'i32', 1: 'u32', 2: 'i64', 3: 'f32', 4: 'f64',
    39→  5: 'u16', 6: 'u8',  7: 'bool8', 8: 'utf8', 9: 'utf8_ref', 10: 'json',
    40→  11: 'bytes', 12: 'i32_array', 13: 'f32_array',
    41→};
    42→
    43→// ─── FNV-1a 32-bit ────────────────────────────────────────────────────────────
    44→
    45→/**
    46→ * FNV-1a 32-bit hash.
    47→ * Math.imul() is a native 32-bit integer multiply — avoids float precision loss
    48→ * that would occur with the plain * operator on large numbers.
    49→ */
    50→function fnv1a32(bytes: Uint8Array): number {
    51→  let hash = 0x811c9dc5; // FNV offset basis
    52→  for (const byte of bytes) {
    53→    hash ^= byte;
    54→    hash  = Math.imul(hash, 0x01000193); // FNV prime
    55→  }
    56→  return hash >>> 0; // coerce to u32
    57→}
    58→
    59→// ─── Encoding ─────────────────────────────────────────────────────────────────
    60→
    61→/**
    62→ * Encode a BinarySchemaDescriptor to bytes for storage in the header.
    63→ * This encoding is the canonical input to schemaFingerprint().
    64→ */
    65→export function encodeSchema(schema: BinarySchemaDescriptor): Uint8Array {
    66→  const encoder     = new TextEncoder();
    67→  const fieldBufs:  Uint8Array[] = [];
    68→  let   totalLen    = 2; // field_count u16
    69→
    70→  for (const field of schema.fields) {
    71→    const nameBytes = encoder.encode(field.name);
    72→    // header: type(1) + flags(1) + byteOffset(2) + nameLen(1) + name(nameLen)
    73→    const rawLen    = 5 + nameBytes.length;
    74→    const paddedLen = Math.ceil(rawLen / 4) * 4;
    75→    const buf       = new Uint8Array(paddedLen); // zero-filled
    76→    const dv        = new DataView(buf.buffer);
    77→
    78→    buf[0] = TYPE_TO_TAG[field.type]!;
    79→    buf[1] = field.flags;
    80→    dv.setUint16(2, field.byteOffset, /* littleEndian */ true);
    81→    buf[4] = nameBytes.length;
    82→    buf.set(nameBytes, 5);
    83→    // Trailing bytes remain zero-padding.
    84→
    85→    fieldBufs.push(buf);
    86→    totalLen += paddedLen;
    87→  }
    88→
    89→  const out = new Uint8Array(totalLen);
    90→  new DataView(out.buffer).setUint16(0, schema.fields.length, true);
    91→
    92→  let cursor = 2;
    93→  for (const fb of fieldBufs) {
    94→    out.set(fb, cursor);
    95→    cursor += fb.length;
    96→  }
    97→
    98→  return out;
    99→}
