   101→// ─── Decoding ─────────────────────────────────────────────────────────────────
   102→
   103→/**
   104→ * Decode a binary schema descriptor read from the header.
   105→ * Returns null if the bytes are truncated or contain an unknown type tag.
   106→ */
   107→export function decodeSchema(bytes: Uint8Array): BinarySchemaDescriptor | null {
   108→  if (bytes.length < 2) return null;
   109→
   110→  const decoder    = new TextDecoder();
   111→  const dv         = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
   112→  const fieldCount = dv.getUint16(0, true);
   113→  const fields:    FieldDescriptor[] = [];
   114→  let   cursor     = 2;
   115→  let   nullableBitIdx = 0;
   116→
   117→  for (let i = 0; i < fieldCount; i++) {
   118→    if (cursor + 5 > bytes.length) return null; // truncated
   119→
   120→    const typeTag    = bytes[cursor]!;
   121→    const flags      = bytes[cursor + 1]!;
   122→    const byteOffset = dv.getUint16(cursor + 2, true);
   123→    const nameLen    = bytes[cursor + 4]!;
   124→    const type       = TAG_TO_TYPE[typeTag];
   125→
   126→    if (type === undefined) return null; // unknown type tag — corrupt or newer version
   127→    if (cursor + 5 + nameLen > bytes.length) return null;
   128→
   129→    const name      = decoder.decode(bytes.subarray(cursor + 5, cursor + 5 + nameLen));
   130→    const rawLen    = 5 + nameLen;
   131→    const paddedLen = Math.ceil(rawLen / 4) * 4;
   132→
   133→    const fd: FieldDescriptor = (flags & FIELD_FLAG_NULLABLE)
   134→      ? { name, type, byteOffset, flags, nullableBitIndex: nullableBitIdx++ }
   135→      : { name, type, byteOffset, flags };
   136→    fields.push(fd);
   137→    cursor += paddedLen;
   138→  }
   139→
   140→  // Recompute record_stride from field layout — the highest (byteOffset + width) + alignment.
   141→  let highWater = 0;
   142→  for (const f of fields) {
   143→    highWater = Math.max(highWater, f.byteOffset + FIELD_BYTE_WIDTHS[f.type]);
   144→  }
   145→  const record_stride = Math.ceil(highWater / 4) * 4;
   146→
   147→  return { fields, record_stride };
   148→}
