   150→// ─── Fingerprint ──────────────────────────────────────────────────────────────
   151→
   152→/**
   153→ * Compute the FNV-1a 32-bit fingerprint of a BinarySchemaDescriptor.
   154→ * Two schemas with identical field names, types, offsets, and flags
   155→ * produce the same fingerprint. Any difference produces a different one.
   156→ */
   157→export function schemaFingerprint(schema: BinarySchemaDescriptor): number {
   158→  return fnv1a32(encodeSchema(schema));
