   177→export function buildSchema(
   178→  fields: ReadonlyArray<{ name: string; type: FieldType; flags?: number }>,
   179→): BinarySchemaDescriptor {
   180→  if (fields.length === 0) {
   181→    throw new TypeError(
   182→      'buildSchema: schema must declare at least one field. ' +
   183→      'A zero-field schema produces record_stride = 0, which breaks ring arithmetic.',
   184→    );
   185→  }
   186→
   187→  const seen = new Set<string>();
   188→  const resolved: FieldDescriptor[] = [];
   189→
   190→  // Reserve null validity bitmap bytes at the very start of each record slot.
   191→  // One bit per nullable field (FIELD_FLAG_NULLABLE). Bitmap size is
   192→  // Math.ceil(nullableCount / 8) bytes; zero if no nullable fields exist.
   193→  const nullableCount = fields.filter(f => f.flags && (f.flags & FIELD_FLAG_NULLABLE)).length;
   194→  const bitmapBytes   = nullableCount > 0 ? Math.ceil(nullableCount / 8) : 0;
   195→
   196→  let offset         = bitmapBytes; // fields start after the bitmap
   197→  let nullableBitIdx = 0;
   198→
   199→  for (const f of fields) {
   200→    if (seen.has(f.name)) {
   201→      throw new TypeError(
   202→        `buildSchema: duplicate field name '${f.name}'. ` +
   203→        `All field names must be unique within a schema.`,
   204→      );
   205→    }
   206→    seen.add(f.name);
   207→
   208→    const width     = FIELD_BYTE_WIDTHS[f.type];
   209→    const alignment = Math.min(width, 4);
   210→
   211→    // Align field to its natural boundary (within the slot, after bitmap bytes).
   212→    const rem = offset % alignment;
   213→    if (rem !== 0) offset += alignment - rem;
   214→
   215→    const flags = f.flags ?? 0;
   216→    const fd: FieldDescriptor = (flags & FIELD_FLAG_NULLABLE)
   217→      ? { name: f.name, type: f.type, byteOffset: offset, flags, nullableBitIndex: nullableBitIdx++ }
   218→      : { name: f.name, type: f.type, byteOffset: offset, flags };
   219→    resolved.push(fd);
   220→    offset += width;
   221→  }
   222→
   223→  const record_stride = Math.ceil(offset / 4) * 4;
   224→  return { fields: resolved, record_stride };
   225→}
